sql:
SELECT ontology_name
FROM ontologies
WHERE ontology_id = 0;

external_knowledge:
; The query assumes that alignment_id is a unique identifier for each alignment, and term_id is a unique identifier for each term in the term_details table; 
; The hierarchical structure of alignments implies a parent-child relationship through source_term_id and target_term_id; 
; The query filters specific term IDs (1 and 2) for term details, indicating these terms are of particular interest.

sql:
SELECT COUNT(*) AS recent_updates
FROM ontologies
WHERE last_updated >= DATE('now', '-1 month');

SELECT alignment_id
FROM alignments
WHERE alignment_id = 1;

SELECT ontology_name, last_updated
FROM ontologies
ORDER BY last_updated DESC;

SELECT a.confidence_score
FROM alignments a
WHERE a.last_updated = (
  SELECT MAX(last_updated)
  FROM alignments
);
